/**
 * @fileoverview Input barrel — re-exports from modular implementation.
 * @module module/Input
 */
import { default as razyui } from '../index.js';
import { InputDef as DEF } from './Input.def.js';
import Input from './Input/index.js';

razyui.Input = Input;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Input);
}

export default Input;

export const stylesheet = null;
