/**
 * @fileoverview Input events — centralised event binding.
 * @module module/Input/events
 */

import { emitEvent } from '../shared/emitEvent.js';

/**
 * Bind input, focus, blur, and clear events.
 *
 * @param {Elements} field — the input element
 * @param {Elements} wrapper — the wrapper element
 * @param {Elements|null} clearBtn — clear button element
 * @param {object} ctx — callbacks
 * @returns {AbortController}
 */
export function bindEvents(field, wrapper, clearBtn, ctx) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };
    const input = field[0];

    input.addEventListener('focus', () => {
        ctx.onFocus?.();
        emitEvent(input, 'focus');
    }, opts);

    input.addEventListener('blur', () => {
        ctx.onBlur?.();
        emitEvent(input, 'blur');
    }, opts);

    input.addEventListener('input', () => {
        const value = input.value;
        ctx.onInput?.(value);
        emitEvent(input, 'input', { value });
        // Show/hide clear button
        if (clearBtn) {
            value ? clearBtn.show() : clearBtn.hide();
        }
    }, opts);

    input.addEventListener('change', () => {
        const value = input.value;
        ctx.onChange?.(value);
        emitEvent(input, 'change', { value });
    }, opts);

    if (clearBtn) {
        clearBtn[0].addEventListener('click', (e) => {
            e.stopPropagation();
            input.value = '';
            clearBtn.hide();
            input.focus();
            ctx.onClear?.();
            ctx.onInput?.('');
            emitEvent(input, 'clear');
            emitEvent(input, 'input', { value: '' });
        }, opts);
    }

    return ac;
}
